121	/// Parse the `--use-template` value into `(code, bot)` template paths.
122	///
123	/// Format: `CODE[,BOT]`. If `BOT` is omitted, the default is the sibling
124	/// directory whose name is `<CODE-basename>.claude` (via
125	/// `Path::with_file_name`, so a trailing slash on `CODE` does not produce
126	/// a different result).
127	pub(crate) fn parse_use_template(
128	    s: &str,
129	) -> Result<(PathBuf, PathBuf), Box<dyn std::error::Error>> {
130	    let mut parts = s.splitn(2, ',');
131	    let code_raw = parts.next().unwrap_or(""); // OK: splitn always yields at least one element
132	    let bot_raw = parts.next();
133	    let code_trim = code_raw.trim();
134	    if code_trim.is_empty() {
135	        return Err("--use-template: code template path is empty".into());
136	    }
137	    let code = PathBuf::from(code_trim);
138	    let bot = match bot_raw.map(str::trim) {
139	        Some(b) if !b.is_empty() => PathBuf::from(b),
140	        _ => {
141	            let file_name = code.file_name().ok_or_else(|| {
142	                format!(
143	                    "--use-template: cannot derive default bot path from '{}' (no file name component)",
144	                    code.display()
145	                )
146	            })?;
147	            let new_name = format!("{}.claude", file_name.to_string_lossy());
148	            code.with_file_name(new_name)
149	        }
150	    };
151	    Ok((code, bot))
152	}
