154	/// Top-level non-hidden files init writes. Kept here so that if init is
155	/// ever extended to write non-hidden top-level files, the pre-flight
156	/// conflict scan flags any template that would clash. Currently empty
157	/// because init only writes hidden files (`.vc-config.toml`, `.gitignore`),
158	/// and the template copy skips hidden entries.
159	const RESERVED_TEMPLATE_ENTRIES: &[&str] = &[];
160	
161	/// Validate one template directory: exists, is a directory, and has no
162	/// top-level non-hidden entry that would collide with init's own writes.
163	///
164	/// - `label` prefixes every error message (`code` / `bot`).
165	pub(crate) fn validate_template_one(
166	    label: &str,
167	    p: &Path,
168	) -> Result<(), Box<dyn std::error::Error>> {
169	    if !p.exists() {
170	        return Err(format!(
171	            "--use-template: {label} template '{}' does not exist",
172	            p.display()
173	        )
174	        .into());
175	    }
176	    if !p.is_dir() {
177	        return Err(format!(
178	            "--use-template: {label} template '{}' is not a directory",
179	            p.display()
180	        )
181	        .into());
182	    }
183	    for entry in std::fs::read_dir(p)? {
184	        let entry = entry?;
185	        let name = entry.file_name();
186	        let name_str = name.to_string_lossy();
187	        if name_str.starts_with('.') {
188	            continue;
189	        }
190	        if RESERVED_TEMPLATE_ENTRIES.contains(&name_str.as_ref()) {
191	            return Err(format!(
192	                "--use-template: {label} template '{}' contains reserved entry '{}'",
193	                p.display(),
194	                name_str
195	            )
196	            .into());
197	        }
198	    }
199	    Ok(())
200	}
