202	/// Validate both template paths (dual-repo mode). Thin wrapper over
203	/// `validate_template_one` kept for single-call ergonomics.
204	pub(crate) fn validate_templates(
205	    code: &Path,
206	    bot: &Path,
207	) -> Result<(), Box<dyn std::error::Error>> {
208	    validate_template_one("code", code)?;
209	    validate_template_one("bot", bot)?;
210	    Ok(())
211	}
