213	/// Recursively copy non-hidden entries from `src` to `dst`. Any entry whose
214	/// file name starts with `.` is skipped. Symlinks are skipped with a debug
215	/// log — templates don't need them, and following them risks escaping the
216	/// template tree.
217	pub(crate) fn copy_template_recursive(
218	    src: &Path,
219	    dst: &Path,
220	) -> Result<(), Box<dyn std::error::Error>> {
221	    for entry in std::fs::read_dir(src)? {
222	        let entry = entry?;
223	        let name = entry.file_name();
224	        let name_str = name.to_string_lossy();
225	        if name_str.starts_with('.') {
226	            continue;
227	        }
228	        let src_path = entry.path();
229	        let dst_path = dst.join(&name);
230	        let ft = entry.file_type()?;
231	        if ft.is_symlink() {
232	            debug!("skip symlink {}", src_path.display());
233	            continue;
234	        }
235	        if ft.is_dir() {
236	            mkdir_p(&dst_path)?;
237	            copy_template_recursive(&src_path, &dst_path)?;
238	        } else if ft.is_file() {
239	            debug!("copy {} -> {}", src_path.display(), dst_path.display());
240	            std::fs::copy(&src_path, &dst_path)?;
241	        }
242	    }
243	    Ok(())
244	}
