393	/// Expand `~` and `$VAR` / `${VAR}` substitutions in a user string.
394	///
395	/// - `~` and `~/…` resolve via `HOME`.
396	/// - Unset env vars are a fatal error (silent empty substitution
397	///   would mask typos).
398	/// - Bare `$` with no identifier after stays literal.
399	pub(crate) fn expand_vars(s: &str) -> Result<String, Box<dyn std::error::Error>> {
400	    let home_expanded = if s == "~" {
401	        std::env::var("HOME").map_err(|_| "HOME is not set; cannot expand '~'")?
402	    } else if let Some(rest) = s.strip_prefix("~/") {
403	        let home = std::env::var("HOME").map_err(|_| "HOME is not set; cannot expand '~/'")?;
404	        format!("{home}/{rest}")
405	    } else {
406	        s.to_string()
407	    };
408	
409	    let mut out = String::with_capacity(home_expanded.len());
410	    let mut chars = home_expanded.chars().peekable();
411	    while let Some(c) = chars.next() {
412	        if c != '$' {
413	            out.push(c);
414	            continue;
415	        }
416	        let (name, braced) = if chars.peek() == Some(&'{') {
417	            chars.next(); // OK: peeked '{' above, next() must yield it
418	            let mut name = String::new();
419	            let mut closed = false;
420	            for c2 in chars.by_ref() {
421	                if c2 == '}' {
422	                    closed = true;
423	                    break;
424	                }
425	                name.push(c2);
426	            }
427	            if !closed {
428	                return Err(format!("unterminated '${{…}}' in '{s}'").into());
429	            }
430	            (name, true)
431	        } else {
432	            let mut name = String::new();
433	            while let Some(&c2) = chars.peek() {
434	                if c2.is_ascii_alphanumeric() || c2 == '_' {
435	                    name.push(c2);
436	                    chars.next();
437	                } else {
438	                    break;
439	                }
440	            }
441	            (name, false)
442	        };
443	        if name.is_empty() {
444	            out.push('$');
445	            if braced {
446	                out.push_str("{}");
447	            }
448	            continue;
449	        }
450	        let val =
451	            std::env::var(&name).map_err(|_| format!("env var '${name}' is not set (in '{s}')"))?;
452	        out.push_str(&val);
453	    }
454	    Ok(out)
455	}
