457	/// True when `s` looks like a git remote URL rather than a path.
458	///
459	/// - Scheme-qualified (`scheme://…`).
460	/// - scp-like SSH form (`user@host:path`).
461	/// - Everything else is treated as a path.
462	pub(crate) fn is_remote_url(s: &str) -> bool {
463	    if s.contains("://") {
464	        return true;
465	    }
466	    if let Some(at) = s.find('@')
467	        && let Some(colon) = s.find(':')
468	        && at < colon
469	        && !s[..at].contains('/')
470	    {
471	        return true;
472	    }
473	    false
474	}
475	
476	/// True when `s` is a GitHub URL (host-based detection).
477	///
478	/// - SSH scp-like (`git@github.com:…`).
479	/// - `ssh://git@github.com/…`.
480	/// - `https://github.com/…` and `http://github.com/…`.
481	/// - GitHub URLs route to the `gh repo create` provisioner.
482	pub(crate) fn is_github_url(s: &str) -> bool {
483	    s.starts_with("git@github.com:")
484	        || s.starts_with("ssh://git@github.com/")
485	        || s.starts_with("https://github.com/")
486	        || s.starts_with("http://github.com/")
487	}
