489	/// Normalize a `--repo local=<parent>` value: expand variables,
490	/// make absolute. Parent doesn't need to exist yet — init creates
491	/// it.
492	pub(crate) fn normalize_local_parent(s: &str) -> Result<PathBuf, Box<dyn std::error::Error>> {
493	    let s = s.trim();
494	    if s.is_empty() {
495	        return Err("--repo local: parent dir is empty".into());
496	    }
497	    let expanded = expand_vars(s)?;
498	    let p = PathBuf::from(&expanded);
499	    if p.is_absolute() {
500	        Ok(p)
501	    } else {
502	        let cwd = std::env::current_dir()?;
503	        Ok(cwd.join(p))
504	    }
505	}
