507	/// Append `.git` to a URL-or-path stem if not already present.
508	///
509	/// - Lets `--repo-remote git@github.com:u/tf1` normalize to the
510	///   same URL the default-mode derivation produces.
511	pub(crate) fn ensure_git_suffix(s: &str) -> String {
512	    if s.ends_with(".git") {
513	        s.to_string()
514	    } else {
515	        format!("{s}.git")
516	    }
517	}
