568	/// Build an `InitPlan` from CLI args + user config.
569	///
570	/// Dispatches on the parsed `<TARGET>` form:
571	///
572	/// - `Url(u)` / `OwnerName(o, n)` → URL is explicit; config not
573	///   consulted; `--account` and `--repo` are rejected as
574	///   meaningless.
575	/// - `Path(p)` → `p` is the destination; basename names the repo;
576	///   remote URL resolved from config via the `--repo` chain.
577	/// - `BareName(n)` → destination at `cwd/<n>`; remote resolved
578	///   from config.
579	///
580	/// The `cfg` parameter is the loaded user config; `init` loads it
581	/// once at entry and passes it through so tests can supply a
582	/// synthetic config without touching disk.
583	pub(crate) fn plan_init(
584	    params: &InitParams,
585	    cfg: &UserConfig,
586	) -> Result<InitPlan, Box<dyn std::error::Error>> {
587	    debug!(
588	        "init args: target={:?}, name={:?}, account={:?}, repo={:?}, por={}, private={}",
589	        params.target, params.name, params.account, params.repo, params.por, params.private
590	    );
591	
592	    let scope = if params.por {
593	        Scope(vec![Side::Code])
594	    } else {
595	        Scope(vec![Side::Code, Side::Bot])
596	    };
597	
598	    if scope.is_code_only()
599	        && let Some(t) = &params.use_template
600	        && t.contains(',')
601	    {
602	        return Err(format!(
603	            "--por takes a single template path; got '{t}' (drop the `,BOT` half)"
604	        )
605	        .into());
606	    }
607	
608	    if params.config.is_some() && !params.por {
609	        return Err(
610	            "--config is only valid with --por (dual configs are per-side and unconditional)"
611	                .into(),
612	        );
613	    }
614	    if let Some(ConfigKind::Path(p)) = &params.config
615	        && !p.exists()
616	    {
617	        return Err(format!("--config: path does not exist: {}", p.display()).into());
618	    }
619	
620	    let parsed = parse_target(&params.target)?;
621	    debug!("parse_target: {:?} → {:?}", params.target, parsed);
622	    let plan = match parsed {
623	        Target::Url(url) => plan_from_url(params, scope, url),
624	        Target::OwnerName(o, n) => {
625	            plan_from_url(params, scope, format!("git@github.com:{o}/{n}.git"))
626	        }
627	        Target::Path(p) => plan_from_path(params, scope, p, cfg),
628	        Target::BareName(n) => plan_from_bare_name(params, scope, n, cfg),
629	    }?;
630	    debug!(
631	        "plan_init: project_dir={}, name={}, code_url={}, provisioner={:?}, gh_code_slug={:?}, code_bare_path={:?}, session_url={:?}",
632	        plan.project_dir.display(),
633	        plan.name,
634	        plan.code_url,
635	        plan.provisioner,
636	        plan.gh_code_slug,
637	        plan.code_bare_path,
638	        plan.session_url,
639	    );
640	    Ok(plan)
641	}
