643	/// Plan when TARGET is a URL or `owner/name` shorthand.
644	///
645	/// - URL is explicit; config not consulted.
646	/// - `--account` / `--repo` are rejected (would have no effect).
647	/// - `[NAME]` overrides the URL-derived directory name.
648	fn plan_from_url(
649	    params: &InitParams,
650	    scope: Scope,
651	    url: String,
652	) -> Result<InitPlan, Box<dyn std::error::Error>> {
653	    if params.account.is_some() {
654	        return Err(
655	            "--account is meaningless with a URL or owner/name TARGET (config not consulted)"
656	                .into(),
657	        );
658	    }
659	    if params.repo.is_some() {
660	        return Err(
661	            "--repo is meaningless with a URL or owner/name TARGET (config not consulted)".into(),
662	        );
663	    }
664	    let code_url = ensure_git_suffix(&url);
665	    let derived_name = derive_name(&code_url)?;
666	    let name = params.name.clone().unwrap_or(derived_name);
667	    let cwd = std::env::current_dir()?;
668	    let project_dir = cwd.join(&name);
669	
670	    let provisioner = if is_github_url(&code_url) {
671	        Provisioner::GhCreate
672	    } else {
673	        Provisioner::ExternalPreExisting
674	    };
675	    let gh_code_slug = if provisioner == Provisioner::GhCreate {
676	        Some(github_slug_from_url(&code_url)?)
677	    } else {
678	        None
679	    };
680	
681	    build_plan(
682	        scope,
683	        name,
684	        project_dir,
685	        code_url,
686	        provisioner,
687	        gh_code_slug,
688	    )
689	}
