691	/// Plan when TARGET is a path. Path IS the destination; basename
692	/// names the repo. Remote resolved via the `--repo` chain.
693	fn plan_from_path(
694	    params: &InitParams,
695	    scope: Scope,
696	    path: PathBuf,
697	    cfg: &UserConfig,
698	) -> Result<InitPlan, Box<dyn std::error::Error>> {
