890	/// Resolve a Path target to an absolute `PathBuf`. Handles `~`,
891	/// `~/X`, `$VAR`, `${VAR}` expansion; makes relative paths
892	/// absolute against cwd; lexically normalizes `.` / `..`. The
893	/// resulting path is **not** required to exist (init creates it).
894	fn resolve_path_target(p: &Path) -> Result<PathBuf, Box<dyn std::error::Error>> {
895	    let s = p.to_str().ok_or("path TARGET is not valid UTF-8")?;
896	    let expanded = expand_vars(s)?;
897	    let pb = PathBuf::from(&expanded);
898	    let abs = if pb.is_absolute() {
899	        pb
900	    } else {
901	        std::env::current_dir()?.join(pb)
902	    };
903	    Ok(normalize_path(&abs))
904	}
905	
906	/// Lexically normalize a path: collapse `.` / `..` components
907	/// without touching disk. `std::fs::canonicalize` requires the
908	/// path to exist, but init's destination doesn't yet.
909	fn normalize_path(p: &Path) -> PathBuf {
910	    let mut out: Vec<std::path::Component> = Vec::new();
911	    for comp in p.components() {
912	        match comp {
913	            std::path::Component::ParentDir => {
914	                let pop = matches!(
915	                    out.last(),
916	                    Some(std::path::Component::Normal(_)) | Some(std::path::Component::CurDir)
917	                );
918	                if pop {
919	                    out.pop();
920	                } else {
921	                    out.push(comp);
922	                }
923	            }
924	            std::path::Component::CurDir => {}
925	            other => out.push(other),
926	        }
927	    }
928	    out.iter().collect()
929	}
