931	/// Extract the `owner/name` slug from a GitHub URL (any of the
932	/// supported forms: SSH scp-like, `ssh://`, `https://`).
933	fn github_slug_from_url(url: &str) -> Result<String, Box<dyn std::error::Error>> {
934	    let stem = url.strip_suffix(".git").unwrap_or(url);
935	    // The slug is the last two path components, `owner/name`.
936	    if let Some(path) = stem
937	        .strip_prefix("git@github.com:")
938	        .or_else(|| stem.strip_prefix("ssh://git@github.com/"))
939	        .or_else(|| stem.strip_prefix("https://github.com/"))
940	        .or_else(|| stem.strip_prefix("http://github.com/"))
941	    {
942	        let parts: Vec<&str> = path.split('/').collect();
943	        if parts.len() >= 2 {
944	            return Ok(format!(
945	                "{}/{}",
946	                parts[parts.len() - 2],
947	                parts[parts.len() - 1]
948	            ));
949	        }
950	    }
951	    Err(format!("cannot extract owner/name slug from GitHub URL '{url}'").into())
952	}
