957	    /// Delegate to the existing `From<&InitArgs>` impl in
958	    /// [`crate::init::params`] (total — never fails).
959	    fn to_params(&self) -> Result<Self::Params, String> {
960	        Ok(InitParams::from(self))
961	    }
