969	/// Init entry point — runs the dual or POR provisioning flow.
970	///
971	/// Takes the shared `Context` (loaded user config) and the flat
972	/// `InitParams`. CLI builds both at the binary edge in main.rs;
973	/// tests construct `InitParams` directly.
974	///
975	/// `params.create_symlink` controls the `~/.claude/projects/`
976	/// symlink side effect:
977	///
978	/// - `true` — CLI behavior; step 11 creates the symlink for
979	///   dual-scope runs.
980	/// - `false` — suppresses that side effect; used by test
981	///   harnesses (`test_helpers::Fixture`, `test_helpers::FixturePor`)
982	///   so parallel fixtures don't collide on the user's home dir.
983	pub fn init(ctx: &Context, params: &InitParams) -> Result<(), Box<dyn std::error::Error>> {
984	    debug!("init: enter");
985	
986	    let create_symlink = params.create_symlink;
987	    let cfg = &ctx.user_config;
988	    let plan = plan_init(params, cfg)?;
989	    let is_dual = plan.scope.is_both();
990	
991	    // --- Preflight ---
992	    info!("Preflight checks...");
993	
994	    debug!("verify jj is installed");
995	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
996	
997	    if plan.provisioner == Provisioner::GhCreate {
998	        debug!("verify gh CLI is installed + authenticated");
999	        run("gh", &["auth", "status"], Path::new("."))
1000	            .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
1001	    }
1002	
1003	    if plan.project_dir.exists() {
1004	        return Err(format!("'{}' already exists", plan.project_dir.display()).into());
1005	    }
1006	
1007	    match &plan.provisioner {
1008	        Provisioner::GhCreate => {
1009	            #[allow(clippy::unwrap_used)]
1010	            let code_slug = plan.gh_code_slug.as_ref().unwrap(); // OK: GhCreate path always sets gh_code_slug
1011	            let (code_owner, code_name) = split_slug(code_slug)?;
1012	            if gh_repo_exists(code_owner, code_name)? {
1013	                return Err(format!("GitHub repo '{code_slug}' already exists").into());
1014	            }
1015	            if let Some(session_slug) = plan.gh_session_slug.as_ref() {
1016	                let (session_owner, session_name) = split_slug(session_slug)?;
1017	                if gh_repo_exists(session_owner, session_name)? {
1018	                    return Err(format!("GitHub repo '{session_slug}' already exists").into());
1019	                }
1020	            }
1021	        }
1022	        Provisioner::LocalBareInit => {
1023	            #[allow(clippy::unwrap_used)]
1024	            let code_bare = plan.code_bare_path.as_ref().unwrap(); // OK: LocalBareInit path always sets code_bare_path
1025	            if code_bare.exists() {
1026	                return Err(format!(
1027	                    "bare repo '{}' already exists; refusing to clobber",
1028	                    code_bare.display()
1029	                )
1030	                .into());
1031	            }
1032	            if let Some(session_bare) = plan.session_bare_path.as_ref()
1033	                && session_bare.exists()
1034	            {
1035	                return Err(format!(
1036	                    "bare repo '{}' already exists; refusing to clobber",
1037	                    session_bare.display()
1038	                )
1039	                .into());
1040	            }
1041	        }
1042	        Provisioner::ExternalPreExisting => {
1043	            // For path-shaped URLs: the path must exist (caller
1044	            // pre-created with `git init --bare`). For scheme-URL
1045	            // values we can't preflight cheaply — let git push
1046	            // surface failures.
1047	            if !is_remote_url(&plan.code_url) {
1048	                let p = PathBuf::from(&plan.code_url);
1049	                if !p.exists() {
1050	                    return Err(format!(
1051	                        "--repo-remote: code path '{}' does not exist — \
1052	                         pre-create with `git init --bare`, or use --repo-local for fixture creation",
1053	                        p.display()
1054	                    )
1055	                    .into());
1056	                }
1057	            }
1058	            if let Some(session_url) = plan.session_url.as_ref()
1059	                && !is_remote_url(session_url)
1060	            {
1061	                let p = PathBuf::from(session_url);
1062	                if !p.exists() {
1063	                    return Err(format!(
1064	                        "--repo-remote: session path '{}' does not exist — \
1065	                         pre-create with `git init --bare`, or use --repo-local for fixture creation",
1066	                        p.display()
1067	                    )
1068	                    .into());
1069	                }
1070	            }
1071	        }
1072	    }
1073	
1074	    let templates = match &params.use_template {
1075	        Some(s) => {
1076	            let (code_t, bot_t) = parse_use_template(s)?;
1077	            if is_dual {
1078	                validate_templates(&code_t, &bot_t)?;
1079	                Some((code_t, Some(bot_t)))
1080	            } else {
1081	                validate_template_one("code", &code_t)?;
1082	                Some((code_t, None))
1083	            }
1084	        }
1085	        None => None,
1086	    };
1087	
1088	    let visibility = if params.private {
1089	        "--private"
1090	    } else {
1091	        "--public"
1092	    };
1093	
1094	    if params.dry_run {
1095	        info!("Dry run — would execute:");
1096	        info!("  1. Create directories: {}", plan.project_dir.display());
1097	        info!(
1098	            "  2. git init + jj git init --colocate on {}",
1099	            if is_dual {
1100	                "both repos"
1101	            } else {
1102	                "the work repo"
1103	            }
1104	        );
1105	        info!(
